"""TLM e-commerce dashboard web app (Cloud Run service).

Thin password gate + static server. It renders a login screen, and once a session
is authenticated it serves `dashboard.html` and proxies the private `tlm.json`
from GCS at `/data.json`. All presentation logic — the Overview / Google Ads /
Trade Desk / Performance tabs and every chart — lives in `dashboard.html`;
this file only decides *who* may see it, not *what* it shows.

Same service pattern as client_resetdata/dash/main.py (byte-for-byte on the auth/serve/
proxy logic); only the login-page branding and the default data object differ. The
org policy that blocks --allow-unauthenticated is handled the same way — the deploy
flips --no-invoker-iam-check so this app's own password gate is the only door.
"""
import os
import hmac
from pathlib import Path
from flask import (
    Flask, request, redirect, session, Response, render_template_string, abort
)
from google.cloud import storage

app = Flask(__name__)
app.secret_key = os.environ["SESSION_SECRET"]
app.config.update(
    SESSION_COOKIE_HTTPONLY=True,
    SESSION_COOKIE_SECURE=True,
    SESSION_COOKIE_SAMESITE="None",  # cross-site iframe on dashboards.bidbrain.ai (None requires Secure)
    PERMANENT_SESSION_LIFETIME=60 * 60 * 12,  # stay logged in 12h
)

# --- config (injected by Cloud Run) ------------------------------------------
DASH_PASSWORD = os.environ["DASH_PASSWORD"].strip()         # from Secret Manager; .strip() guards against stray whitespace/CRLF baked into the secret on Windows
GCS_BUCKET = os.environ["GCS_BUCKET"]                        # private data bucket
DATA_OBJECT = os.environ.get("DATA_OBJECT", "tlm.json")       # object inside it

_storage = storage.Client()

# Dashboard HTML is baked into the container at build time, next to this file.
# Anchor to __file__ so it loads regardless of the process working directory.
try:
    DASHBOARD_HTML = (Path(__file__).resolve().parent / "dashboard.html").read_text(encoding="utf-8")
except FileNotFoundError:
    DASHBOARD_HTML = None

# ============================================================================
# Branding: the 100% Digital agency mark + the real white The Little Marionette
# wordmark are inlined as base64 (from client_tlm/creatives/). The login keeps a
# dark slate ground so the white logo reads; the DASHBOARD itself is light cream +
# slate-blue accent (#4F7290), matching thelittlemarionette.com. The marionette
# logo fills the __LOGIN_LOGO_SRC__ token below (run creatives/inject_logos.py).
# ============================================================================
LOGIN_HTML = """<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>The Little Marionette · Performance Dashboard</title>
<style>
  *{box-sizing:border-box}
  body{margin:0;min-height:100vh;display:flex;align-items:center;justify-content:center;
       font-family:-apple-system,BlinkMacSystemFont,"Inter","Segoe UI",Roboto,sans-serif;
       background:radial-gradient(1200px 600px at 50% -10%,#24323F 0%,#16212B 55%,#0C1218 100%)}
  .card{width:100%;max-width:360px;padding:36px 32px;background:#16212B;
        border:1px solid rgba(79,114,144,.28);border-radius:16px;
        box-shadow:0 20px 64px rgba(0,0,0,.55)}
  .logo{display:flex;align-items:center;justify-content:center;gap:13px;margin-bottom:8px}
  .logo .agency{height:26px;width:auto;display:block}
  .logo .divider{width:1px;height:26px;background:#2C3A47;display:inline-block}
  .logo .client{height:26px;width:auto;display:block}
  .brand{font-size:10.5px;font-weight:700;letter-spacing:1.8px;color:#7FA6C2;margin:14px 0;text-align:center}
  h1{font-size:18px;font-weight:700;margin:0 0 4px;color:#EDE6DA;text-align:center}
  p{font-size:13px;color:#9FB1BE;margin:0 0 22px;text-align:center}
  input{width:100%;padding:12px 13px;font-size:15px;color:#EDE6DA;background:#0F171E;
        border:1px solid #2C3A47;border-radius:10px;outline:none}
  input::placeholder{color:#6E7E89}
  input:focus{border-color:#4F7290;box-shadow:0 0 0 3px rgba(79,114,144,.25)}
  button{width:100%;margin-top:12px;padding:12px;font-size:15px;font-weight:700;cursor:pointer;
         background:#4F7290;color:#fff;border:none;border-radius:10px}
  button:hover{background:#3F5D77}
  .err{margin-top:12px;font-size:13px;color:#FB7185;min-height:16px;text-align:center}
</style>
</head>
<body>
  <form class="card" method="POST" action="/login">
    <!-- 100% Digital agency mark · divider · The Little Marionette wordmark -->
    <div class="logo">
      <img class="agency" src="data:image/webp;base64," alt="100% Digital">
      <span class="divider"></span>
      <img class="client" src="data:image/png;base64," alt="The Little Marionette">
    </div>
    <div class="brand">100% DIGITAL · THE LITTLE MARIONETTE</div>
    <h1>Dashboard access</h1>
    <p>Enter the password to continue.</p>
    <input type="password" name="password" placeholder="Password" autofocus
           autocomplete="current-password">
    <button type="submit">Unlock</button>
    <div class="err">{{ error or "" }}</div>
  </form>
</body>
</html>"""


def authed():
    return session.get("ok") is True


@app.get("/")
def home():
    if not authed():
        return render_template_string(LOGIN_HTML, error=None)
    if DASHBOARD_HTML is None:
        return Response("dashboard.html is missing from the deploy.", status=500)
    # no-store so a redeploy of the dashboard is picked up immediately, never
    # served stale from the browser or any proxy (matches /data.json).
    return Response(DASHBOARD_HTML, mimetype="text/html",
                    headers={"Cache-Control": "no-store"})


@app.post("/login")
def login():
    if hmac.compare_digest(request.form.get("password", ""), DASH_PASSWORD):
        session["ok"] = True
        session.permanent = True
        return redirect("/")
    return render_template_string(LOGIN_HTML, error="Incorrect password."), 401


@app.get("/logout")
def logout():
    session.clear()
    return redirect("/")


@app.get("/data.json")
def data():
    # The dashboard fetches this. Only an authenticated session gets it;
    # everyone else gets 401. The bucket itself stays private.
    if not authed():
        abort(401)
    blob = _storage.bucket(GCS_BUCKET).blob(DATA_OBJECT)
    if not blob.exists():
        abort(404)
    return Response(
        blob.download_as_bytes(),
        mimetype="application/json",
        headers={"Cache-Control": "no-store"},
    )


@app.get("/healthz")
def healthz():
    return "ok"


if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.environ.get("PORT", 8080)))